/// UUID Generator that creates RFC 4122 version 4 compliant UUIDs
/// using Dart's Random class without external packages.
class UUIDGenerator {
  static final Random _random = Random.secure();

  /// Generates a single UUID v4 string.
  static String generate() {
    final bytes = List<int>.generate(16, (_) => _random.nextInt(256));

    // Set version to 4 (0100 in binary) in byte 6
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to 10xx in binary in byte 8
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatUUID(bytes);
  }

  /// Generates a timestamp-prefixed UUID for sortable offline entries.
  static String generateTimestamped() {
    final now = DateTime.now().millisecondsSinceEpoch;
    final timestampHex = now.toRadixString(16).padLeft(12, '0');
    final uuid = generate();
    // Replace the first segment with timestamp-based hex
    return '${timestampHex.substring(0, 8)}-${timestampHex.substring(8, 12)}-${uuid.substring(19)}';
  }

  /// Generates a deterministic UUID v5-like identifier from a namespace and name.
  static String generateFromName(String namespace, String name) {
    final input = '$namespace:$name';
    final bytes = utf8.encode(input);

    // Simple hash-based generation (not cryptographic, but deterministic)
    final hash = List<int>.filled(16, 0);
    for (int i = 0; i < bytes.length; i++) {
      hash[i % 16] = (hash[i % 16] + bytes[i]) & 0xFF;
      // Mix bits
      hash[i % 16] ^= (bytes[i] << (i % 5)) & 0xFF;
      hash[(i + 7) % 16] = (hash[(i + 7) % 16] ^ (bytes[i] >> 3)) & 0xFF;
    }

    // Additional mixing rounds for better distribution
    for (int round = 0; round < 4; round++) {
      for (int i = 0; i < 16; i++) {
        hash[i] = (hash[i] + hash[(i + 1) % 16] * 31 + round) & 0xFF;
        hash[(i + 5) % 16] ^= (hash[i] >> 2);
      }
    }

    // Set version to 5
    hash[6] = (hash[6] & 0x0F) | 0x50;
    hash[8] = (hash[8] & 0x3F) | 0x80;

    return _formatUUID(hash);
  }

  /// Generates a short ID (8 characters) for display purposes.
  static String generateShortId() {
    final bytes = List<int>.generate(4, (_) => _random.nextInt(256));
    return bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join('');
  }

  /// Formats 16 bytes into a standard UUID string format.
  static String _formatUUID(List<int> bytes) {
    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join('');
    return '${hex.substring(0, 8)}-${hex.substring(8, 12)}-'
        '${hex.substring(12, 16)}-${hex.substring(16, 20)}-'
        '${hex.substring(20, 32)}';
  }

  /// Validates whether a string is a valid UUID format.
  static bool isValidUUID(String uuid) {
    final regex = RegExp(
      r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$',
      caseSensitive: false,
    );
    return regex.hasMatch(uuid);
  }
}

/// Represents an offline data entry with a generated UUID.
class OfflineRecord {
  final String id;
  final String title;
  final String content;
  final DateTime createdAt;
  bool isSynced;

  OfflineRecord({
    required this.id,
    required this.title,
    required this.content,
    required this.createdAt,
    this.isSynced = false,
  });

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'title': title,
      'content': content,
      'createdAt': createdAt.toIso8601String(),
      'isSynced': isSynced,
    };
  }
}

