class _GenerateTabState extends State<GenerateTab> {
  String _currentUUID = '';
  String _selectedType = 'v4';
  final List<String> _history = [];
  final TextEditingController _namespaceController = TextEditingController(text: 'my-app');
  final TextEditingController _nameController = TextEditingController();
  int _batchCount = 1;

  @override
  void initState() {
    super.initState();
    _generateUUID();
  }

  @override
