  void _generateUUID() {
    setState(() {
      switch (_selectedType) {
        case 'v4':
          _currentUUID = UUIDGenerator.generate();
          break;
        case 'timestamped':
          _currentUUID = UUIDGenerator.generateTimestamped();
          break;
        case 'named':
          final name = _nameController.text.isEmpty ? 'default' : _nameController.text;
          _currentUUID = UUIDGenerator.generateFromName(
            _namespaceController.text,
            name,
          );
          break;
        case 'short':
          _currentUUID = UUIDGenerator.generateShortId();
          break;
      }
      _history.insert(0, _currentUUID);
      if (_history.length > 50) {
        _history.removeLast();
      }
    });
  }

  void _generateBatch() {
    setState(() {
      for (int i = 0; i < _batchCount; i++) {
        String uuid;
        switch (_selectedType) {
          case 'v4':
            uuid = UUIDGenerator.generate();
            break;
          case 'timestamped':
            uuid = UUIDGenerator.generateTimestamped();
            break;
          case 'short':
            uuid = UUIDGenerator.generateShortId();
            break;
          default:
            uuid = UUIDGenerator.generate();
        }
        _history.insert(0, uuid);
      }
      if (_history.isNotEmpty) {
        _currentUUID = _history.first;
      }
      while (_history.length > 200) {
        _history.removeLast();
      }
    });
  }

