class ValidateTab extends StatefulWidget {
  const ValidateTab({super.key});

  @override
  State<ValidateTab> createState() => _ValidateTabState();
}

class _ValidateTabState extends State<ValidateTab> {
  final TextEditingController _validateController = TextEditingController();
  bool? _isValid;
  Map<String, String>? _uuidParts;

  void _validate() {
    final input = _validateController.text.trim();
    final valid = UUIDGenerator.isValidUUID(input);

    setState(() {
      _isValid = valid;
      if (valid) {
        final parts = input.split('-');
        _uuidParts = {
          'Time Low': parts[0],
          'Time Mid': parts[1],
          'Time High & Version': parts[2],
          'Clock Seq & Variant': parts[3],
          'Node': parts[4],
          'Version': _getVersion(parts[2]),
          'Variant': _getVariant(parts[3]),
        };
      } else {
        _uuidParts = null;
      }
    });
  }

  String _getVersion(String timehigh) {
    final versionChar = timehigh[0];
    final version = int.parse(versionChar, radix: 16);
    switch (version) {
      case 1:
        return '1 (Time-based)';
      case 2:
        return '2 (DCE Security)';
      case 3:
        return '3 (MD5 Name-based)';
      case 4:
        return '4 (Random)';
      case 5:
        return '5 (SHA-1 Name-based)';
      default:
        return '$version (Unknown)';
    }
  }

  String _getVariant(String clockSeq) {
    final variantBits = int.parse(clockSeq[0], radix: 16);
    if (variantBits < 8) {
      return 'NCS (backward compatibility)';
    } else if (variantBits < 12) {
      return 'RFC 4122';
    } else if (variantBits < 14) {
      return 'Microsoft (backward compatibility)';
    } else {
      return 'Reserved';
    }
  }

  @override
  void dispose() {
    _validateController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return SingleChildScrollView(
      padding: const EdgeInsets.all(16),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          Card(
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text('Validate UUID', style: theme.textTheme.titleMedium),
                  const SizedBox(height: 12),
                  TextField(
                    controller: _validateController,
                    decoration: InputDecoration(
                      labelText: 'Enter UUID to validate',
                      border: const OutlineInputBorder(),
                      hintText: 'xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx',
                      suffixIcon: IconButton(
                        icon: const Icon(Icons.paste),
                        onPressed: () async {
                          final data = await Clipboard.getData('text/plain');
                          if (data?.text != null) {
                            _validateController.text = data!.text!;
                            _validate();
                          }
                        },
                      ),
                    ),
                    style: const TextStyle(fontFamily: 'monospace'),
                    onSubmitted: (_) => _validate(),
                  ),
                  const SizedBox(height: 12),
                  Row(
                    children: [
                      Expanded(
                        child: FilledButton.icon(
                          onPressed: _validate,
                          icon: const Icon(Icons.check),
                          label: const Text('Validate'),
                        ),
                      ),
                      const SizedBox(width: 8),
                      OutlinedButton(
                        onPressed: () {
                          _validateController.text = UUIDGenerator.generate();
                          _validate();
                        },
                        child: const Text('Test with New'),
                      ),
                    ],
                  ),
                ],
              ),
            ),
          ),
          const SizedBox(height: 16),

          // Validation Result
          if (_isValid != null)
            Card(
              color: _isValid!
                  ? Colors.green.withOpacity(0.1)
                  : Colors.red.withOpacity(0.1),
              child: Padding(
                padding: const EdgeInsets.all(16),
                child: Column(
                  children: [
                    Icon(
                      _isValid! ? Icons.check_circle : Icons.error,
                      size: 48,
                      color: _isValid! ? Colors.green : Colors.red,
                    ),
                    const SizedBox(height: 8),
                    Text(
                      _isValid! ? 'Valid UUID' : 'Invalid UUID',
                      style: theme.textTheme.titleLarge?.copyWith(
                        color: _isValid! ? Colors.green : Colors.red,
                      ),
                    ),
                  ],
                ),
              ),
            ),

          if (_uuidParts != null) ...[
            const SizedBox(height: 16),
            Card(
              child: Padding(
                padding: const EdgeInsets.all(16),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text('UUID Components', style: theme.textTheme.titleMedium),
                    const Divider(),
                    ..._uuidParts!.entries.map((entry) => Padding(
                          padding: const EdgeInsets.symmetric(vertical: 4),
                          child: Row(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              SizedBox(
                                width: 160,
                                child: Text(
                                  entry.key,
                                  style: theme.textTheme.bodySmall?.copyWith(
                                    color: theme.colorScheme.onSurface.withOpacity(0.6),
                                    fontWeight: FontWeight.bold,
                                  ),
                                ),
                              ),
                              Expanded(
                                child: Text(
                                  entry.value,
                                  style: const TextStyle(
                                    fontFamily: 'monospace',
                                    fontSize: 13,
                                  ),
                                ),
                              ),
                            ],
                          ),
                        )),
                  ],
                ),
              ),
            ),
          ],

          const SizedBox(height: 24),

          // Info Card
          Card(
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Row(
                    children: [
                      Icon(Icons.info_outline, color: theme.colorScheme.primary),
                      const SizedBox(width: 8),
                      Text('About UUID Generation', style: theme.textTheme.titleMedium),
                    ],
                  ),
                  const Divider(),
                  const _InfoItem(
                    title: 'V4 (Random)',
                    description: 'Uses cryptographically secure random numbers. Best for general use.',
                  ),
                  const _InfoItem(
                    title: 'Timestamped',
                    description: 'Prefixed with timestamp for natural sorting. Great for ordered records.',
                  ),
                  const _InfoItem(
                    title: 'Named',
                    description: 'Deterministic UUID from namespace + name. Same input = same UUID.',
                  ),
                  const _InfoItem(
                    title: 'Short',
                    description: '8-character hex ID for display purposes. Lower uniqueness guarantee.',
                  ),
                  const SizedBox(height: 8),
                  Text(
                    'Collision probability for V4: ~1 in 5.3 × 10³⁶',
                    style: theme.textTheme.bodySmall?.copyWith(
                      fontStyle: FontStyle.italic,
                      color: theme.colorScheme.onSurface.withOpacity(0.6),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }
}

class _InfoItem extends StatelessWidget {
